import React from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import TaskCard from '../components/Tasks/TaskCard';
import ProjectCard from '../components/Projects/ProjectCard';
import '../styles/Dashboard.css';

const Dashboard = () => {
  const { currentUser } = useAuth();

  // Mock data - in a real app, this would come from an API
  const stats = {
    totalProjects: 3,
    totalTasks: 4,
    inProgress: 2,
    myTasks: 1
  };

  const recentTasks = [
    {
      id: 1,
      title: 'Design homepage layout',
      description: 'Create wireframes and mockups for new homepage design',
      status: 'In Progress',
      project: 'Website Redesign',
      assignee: 'Wayne Travis',
      dueDate: '11/15/2023'
    }
  ];

  const projects = [
    {
      id: 1,
      name: 'Website Redesign',
      description: 'Complete redesign of company website with modern UI/UX',
      manager: 'Wayne Travis',
      dueDate: '12/15/2023',
      progress: 65,
      taskCount: 5
    },
    {
      id: 2,
      name: 'Mobile App Development',
      description: 'New mobile application for iOS and Android platforms',
      manager: 'Sarah Johnson',
      dueDate: '1/20/2024',
      progress: 40,
      taskCount: 5
    },
    {
      id: 3,
      name: 'Q4 Marketing Campaign',
      description: 'End of year marketing initiative',
      manager: 'Wayne Travis',
      dueDate: '11/30/2023',
      progress: 20,
      taskCount: 5
    }
  ];

  const recentActivity = [
    { id: 1, text: 'New task "Design homepage layout" was created', time: '2 hours ago', icon: '➕' },
    { id: 2, text: 'Task "Create marketing materials" was completed', time: '1 day ago', icon: '✅' }
  ];

  return (
    <div className="dashboard-container">
      <header className="dashboard-header">
        <h1>Welcome back, {currentUser?.name || 'User'}! 👋</h1>
        <p>Here's what's happening with your projects today.</p>
      </header>

      {/* Stats Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <span className="stat-icon">📁</span>
          <div className="stat-content">
            <h3>{stats.totalProjects}</h3>
            <p>Total Projects</p>
          </div>
        </div>
        <div className="stat-card">
          <span className="stat-icon">✅</span>
          <div className="stat-content">
            <h3>{stats.totalTasks}</h3>
            <p>Total Tasks</p>
          </div>
        </div>
        <div className="stat-card">
          <span className="stat-icon">🚀</span>
          <div className="stat-content">
            <h3>{stats.inProgress}</h3>
            <p>In Progress</p>
          </div>
        </div>
        <div className="stat-card">
          <span className="stat-icon">🎯</span>
          <div className="stat-content">
            <h3>{stats.myTasks}</h3>
            <p>My Tasks</p>
          </div>
        </div>
      </div>

      <div className="dashboard-content">
        {/* Recent Tasks */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>My Recent Tasks</h2>
            <Link to="/tasks" className="view-all">View All</Link>
          </div>
          <div className="tasks-list">
            {recentTasks.map(task => (
              <TaskCard key={task.id} task={task} />
            ))}
          </div>
        </section>

        {/* Projects */}
        <section className="dashboard-section projects-section">
          <div className="section-header">
            <h2>All Projects</h2>
            <span className="project-count">{projects.length} projects</span>
          </div>
          <div className="projects-grid">
            {projects.map(project => (
              <ProjectCard key={project.id} project={project} />
            ))}
          </div>
        </section>

        {/* Recent Activity */}
        <aside className="recent-activity">
          <h2>Recent Activity</h2>
          <div className="activity-list">
            {recentActivity.map(activity => (
              <div key={activity.id} className="activity-item">
                <span className="activity-icon">{activity.icon}</span>
                <div className="activity-content">
                  <p>{activity.text}</p>
                  <span className="activity-time">{activity.time}</span>
                </div>
              </div>
            ))}
          </div>
        </aside>
      </div>
    </div>
  );
};

export default Dashboard;
